mapper.select:
SELECT s.id, s.shipping_no AS shippingNo, s.order_id AS orderId, o.order_no AS orderNo, o.customer_id AS customerId, c.company_name AS customerName, s.carrier, s.tracking_no AS trackingNo, s.ship_date AS shipDate, s.estimated_arrival AS estimatedArrival, s.actual_arrival AS actualArrival, s.package_count AS packageCount, s.total_volume AS totalVolume, s.total_gross_weight AS totalGrossWeight, s.total_net_weight AS totalNetWeight, s.status, s.customs_status AS customsStatus, s.tracking_data AS trackingData, s.created_by AS createdBy, s.created_time AS createdTime, s.updated_by AS updatedBy, s.updated_time AS updatedTime FROM crm_shipping s LEFT JOIN crm_order o ON s.order_id = o.id AND o.deleted = 0 LEFT JOIN crm_customer c ON o.customer_id = c.id AND c.deleted = 0 WHERE s.deleted = 0
AND s.shipping_no LIKE CONCAT('%', #{query.shippingNo}, '%')
AND s.order_id = #{query.orderId}
AND s.tracking_no LIKE CONCAT('%', #{query.trackingNo}, '%')
AND s.status = #{query.status}
ORDER BY s.created_time DESC
